<body>
  <div class="no-print">
    <button onclick="window.print()">Imprimir Etiqueta</button>
  </div>

  <div class="label-wrap">
    <div class="header">
      <h2>ETIQUETA DE ENVIO</h2>
      <p><strong>Pedido #${v.id.substring(0,8)}</strong> &nbsp;|&nbsp; ${new Date(v.created_at).toLocaleString("pt-BR")}</p>
    </div>

    <div class="section">
      <div class="section-label">Destinatario</div>
      <div class="row"><strong>${v.customer_name||"N/A"}</strong></div>
      <div class="row">Tel: ${v.customer_phone||"N/A"}</div>
      <div class="row">Email: ${v.customer_email||"N/A"}</div>
    </div>

    <div class="address-box">
      <div class="section-label">Endereco de Entrega</div>
      <div class="row"><strong>${ae}, ${Ot}</strong></div>
      ${Ie?`<div class="row">Compl: ${Ie}</div>`:""}
      <div class="row">Bairro: ${an}</div>
      <div class="row">Cidade: ${ut} - ${yt}</div>
      <div class="row">CEP: <strong>${se}</strong></div>
    </div>

    <div class="section">
      <div class="section-label">Produtos</div>
      ${M||'<div class="row">Nenhum produto</div>'}
    </div>

    <div class="totals">
      <div class="row"><strong>Total: R$ ${v.total_amount.toFixed(2)}</strong></div>
      <div class="row">Pagamento: ${v.payment_method==="pix"?"PIX":"Dinheiro"}</div>
      <div class="row">Status: ${v.payment_status==="paid"?"Pago":"Pendente"}</div>
    </div>
  </div>

  <div class="no-print">
    <button onclick="window.print()">Imprimir Etiqueta</button>
  </div>
</body>
